import{_ as o,o as t,c as d,ag as c}from"./chunks/framework.CxQaEjLZ.js";const u=JSON.parse('{"title":"How It Works","description":"","frontmatter":{},"headers":[],"relativePath":"how-it-works.md","filePath":"how-it-works.md"}'),r={name:"how-it-works.md"};function a(s,e,i,n,l,p){return t(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h1><p>depretec runs two passes over a TypeScript Program built via <a href="https://ts-morph.com" target="_blank" rel="noreferrer">ts-morph</a>.</p><h2 id="file-discovery" tabindex="-1">File discovery <a class="header-anchor" href="#file-discovery" aria-label="Permalink to &quot;File discovery&quot;">​</a></h2><p>depretec never loads your whole dependency tree. Instead:</p><ol><li><strong>Inside a git repo</strong>: uses <code>git ls-files --cached --others --exclude-standard</code> scoped to the target directory. This automatically honors <code>.gitignore</code>, <code>.git/info/exclude</code>, and the user&#39;s global <code>core.excludesfile</code> — so generated code, build outputs, caches, and minified files are skipped without any config.</li><li><strong>Outside a git repo</strong>: falls back to a broad <code>**/*.{ts,tsx,js,jsx,mts,cts,mjs,cjs}</code> glob with minimal excludes (<code>node_modules</code>, <code>dist</code>, <code>build</code>, <code>*.min.*</code>).</li><li><strong>With <code>--include</code></strong>: user-supplied globs take over entirely.</li></ol><p>On top of that, any file whose first 512 bytes contain <code>@generated</code>, <code>GENERATED FILE/CODE</code>, or <code>DO NOT EDIT</code> is skipped. This catches Prisma clients, GraphQL codegen output, protobuf, Flow, and other tools that follow the generated-code convention.</p><p><code>.d.ts</code> files in <code>node_modules</code> are <strong>never</strong> explicitly loaded — the TypeScript type checker resolves them lazily when it needs to, keeping memory proportional to imports rather than dep count.</p><h2 id="pass-1-collect-deprecated-declarations-user-source" tabindex="-1">Pass 1: Collect deprecated declarations (user source) <a class="header-anchor" href="#pass-1-collect-deprecated-declarations-user-source" aria-label="Permalink to &quot;Pass 1: Collect deprecated declarations (user source)&quot;">​</a></h2><p>Walks every declaration in the project&#39;s source files — <code>function</code>, <code>method</code>, <code>class</code>, <code>property</code>, <code>variable</code>, <code>type</code>, <code>interface</code>, <code>enum</code>, and accessor — and checks for a <code>@deprecated</code> JSDoc tag.</p><p>Produces the <code>deprecations</code> list in the report (user-declared deprecated symbols).</p><h2 id="pass-2-match-identifiers-lazily" tabindex="-1">Pass 2: Match identifiers lazily <a class="header-anchor" href="#pass-2-match-identifiers-lazily" aria-label="Permalink to &quot;Pass 2: Match identifiers lazily&quot;">​</a></h2><p>Every identifier in your source files is resolved through the TypeScript type checker. For each identifier:</p><ol><li>Get its symbol (follows re-exports and aliases)</li><li>For each declaration of that symbol, check for <code>@deprecated</code> JSDoc</li><li>If found, record an occurrence</li></ol><p>This pass handles both user-defined and dependency-defined deprecations. TypeScript loads the relevant <code>.d.ts</code> on demand — we never pre-scan <code>node_modules</code>.</p><p>The checker follows:</p><ul><li>Re-exports (<code>export { foo } from &#39;./bar&#39;</code>)</li><li>Method chains (<code>z.string().email()</code> resolves through each call)</li><li>Property access (<code>obj.deprecatedProp</code>)</li></ul><h2 id="replacement-extraction" tabindex="-1">Replacement extraction <a class="header-anchor" href="#replacement-extraction" aria-label="Permalink to &quot;Replacement extraction&quot;">​</a></h2><p>For each deprecated declaration, depretec tries to extract the replacement hint in this order:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Example JSDoc</th></tr></thead><tbody><tr><td><code>{@link X}</code></td><td><code>@deprecated Use {@link newFn} instead</code></td></tr><tr><td><code>{@linkcode X}</code></td><td><code>@deprecated {@linkcode newFn}</code></td></tr><tr><td><code>{@linkplain X}</code></td><td><code>@deprecated {@linkplain newFn}</code></td></tr><tr><td>Free-text: use</td><td><code>@deprecated Use \\</code>newFn` instead`</td></tr><tr><td>Free-text: replaced by</td><td><code>@deprecated Replaced by \\</code>newFn``</td></tr><tr><td>Free-text: prefer</td><td><code>@deprecated Prefer \\</code>newFn``</td></tr><tr><td>Bareword variants</td><td><code>@deprecated newFn</code></td></tr></tbody></table><p>If no hint is found, <code>replacement</code> is <code>null</code>.</p><h2 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h2><ul><li><strong>Auto-fix</strong> - writing replacements back to files (planned for <code>--fix</code>)</li><li><strong><code>.vue</code> / <code>.svelte</code> / <code>.astro</code></strong> - only <code>.ts</code>, <code>.tsx</code>, <code>.js</code>, <code>.jsx</code>, <code>.d.ts</code></li><li><strong>Runtime detection</strong> - only static analysis via JSDoc, not runtime <code>console.warn</code> deprecations</li></ul>',22)])])}const f=o(r,[["render",a]]);export{u as __pageData,f as default};
